={{ (() => {
  const txt = ($json.body?.chatInput || $json.chatInput || "").toLowerCase();

  const meses = {
    enero: "01",
    febrero: "02",
    marzo: "03",
    abril: "04",
    mayo: "05",
    junio: "06",
    julio: "07",
    agosto: "08",
    septiembre: "09",
    setiembre: "09",
    octubre: "10",
    noviembre: "11",
    diciembre: "12"
  };

  const fecha = txt.match(/(\d{1,2})\s+de\s+([a-záéíóúñ]+)\s+de\s+(\d{4})/i);
  const hora = txt.match(/(\d{1,2}):(\d{2})/);

  if (!fecha || !hora) return "";

  const dia = fecha[1].padStart(2, "0");
  const mesTexto = fecha[2].toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g, "");
  const mes = meses[mesTexto];
  const anio = fecha[3];
  const hh = hora[1].padStart(2, "0");
  const mm = hora[2];

  if (!mes) return "";

  return `${anio}-${mes}-${dia}T${hh}:${mm}:00`;
})() }}

={{ (() => {
  const txt = ($json.body?.chatInput || $json.chatInput || "").toLowerCase();

  const meses = {
    enero: "01",
    febrero: "02",
    marzo: "03",
    abril: "04",
    mayo: "05",
    junio: "06",
    julio: "07",
    agosto: "08",
    septiembre: "09",
    setiembre: "09",
    octubre: "10",
    noviembre: "11",
    diciembre: "12"
  };

  const fecha = txt.match(/(\d{1,2})\s+de\s+([a-záéíóúñ]+)\s+de\s+(\d{4})/i);
  const hora = txt.match(/(\d{1,2}):(\d{2})/);

  if (!fecha || !hora) return "";

  const dia = fecha[1].padStart(2, "0");
  const mesTexto = fecha[2].toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g, "");
  const mes = meses[mesTexto];
  const anio = fecha[3];

  let hh = Number(hora[1]);
  let mm = Number(hora[2]) + 30;

  if (mm >= 60) {
    hh += 1;
    mm -= 60;
  }

  if (!mes) return "";

  return `${anio}-${mes}-${dia}T${String(hh).padStart(2, "0")}:${String(mm).padStart(2, "0")}:00`;
})() }}

