    nombre_mascota: limpiar(
      $json.nombreMascota 
      || $json.nombre_mascota 
      || $json.body?.nombreMascota 
      || mascotaPorEtiqueta 
      || mascotaPorFrase 
      || ""
    ),

    tipo_mascota: limpiar(
      $json.tipoMascota 
